'use client'

import { useState, useEffect } from 'react'
import Image from 'next/image'
import { ChevronLeft, ChevronRight, ArrowRight, Cloud, Shield, Zap } from 'lucide-react'

const slides = [
    {
        id: 1,
        image: '/assets/img/projectimg1.jpg',
        title: 'Alpha Cloud Solutions',
        desc: 'Unlock the full potential of cloud computing.',
        // We can keep the text/overlay if the user wants, or just the image. 
        // The user said "images in carousel should be projectimg 1, 2 and 3". 
        // Usually carousel images are full slides. I'll render the image and maybe overlay some text if needed, 
        // but for now I'll make the image the main content of the "screen".
    },
    {
        id: 2,
        image: '/assets/img/projectimg2.jpg',
        title: 'Feature Two',
        desc: 'Powerful reliable features for your business.',
    },
    {
        id: 3,
        image: '/assets/img/projectimg3.jpg',
        title: 'Feature Three',
        desc: 'Scale globally with ease.',
    }
]

export default function FeaturedProject() {
    const [current, setCurrent] = useState(0)

    const nextSlide = () => {
        setCurrent((prev) => (prev === slides.length - 1 ? 0 : prev + 1))
    }

    const prevSlide = () => {
        setCurrent((prev) => (prev === 0 ? slides.length - 1 : prev - 1))
    }

    // Auto-advance
    useEffect(() => {
        const timer = setInterval(nextSlide, 5000)
        return () => clearInterval(timer)
    }, [])

    return (
        <section className="relative px-4 pb-20 -mt-20 z-20">
            <div className="max-w-[728px] mx-auto">
                {/* Device Frame with monobg.jpg as texture/background */}
                <div className="relative rounded-[40px] p-3 shadow-2xl overflow-hidden">
                    {/* Animated Background Layer */}
                    <div
                        className="absolute inset-[-100%] bg-cover bg-center animate-spin-slow"
                        style={{
                            backgroundImage: `url('/assets/img/monobg.jpg')`,
                        }}
                    />

                    {/* Content Layer */}
                    <div className="relative z-10">
                        {/* Inner Bezel/Border (Black/Dark screen border) */}
                        <div className="rounded-[30px] overflow-hidden">
                            {/* Screen Content */}
                            <div className="relative aspect-[16/9] md:aspect-[16/8] bg-white rounded-[28px] overflow-hidden group">

                                {/* Slides */}
                                <div className="absolute inset-0 transition-opacity duration-700 ease-in-out">
                                    <Image
                                        src={slides[current].image}
                                        alt={`Slide ${current + 1}`}
                                        fill
                                        className="object-cover object-top"
                                        priority
                                    />
                                </div>

                                {/* Overlay Content (Optional - mimicking the Alpha text if appropriate, or just controls) */}
                                {/* If the images ALREADY contain the text (they are screenshots of the design), we don't need overlay text. 
                                Assuming they are screenshots based on names. I'll add subtle controls. */}

                                {/* Controls */}
                                <button
                                    onClick={prevSlide}
                                    className="absolute left-4 top-1/2 -translate-y-1/2 w-10 h-10 bg-white/80 hover:bg-white rounded-full flex items-center justify-center shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"
                                >
                                    <ChevronLeft className="w-6 h-6 text-gray-800" />
                                </button>

                                <button
                                    onClick={nextSlide}
                                    className="absolute right-4 top-1/2 -translate-y-1/2 w-10 h-10 bg-white/80 hover:bg-white rounded-full flex items-center justify-center shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"
                                >
                                    <ChevronRight className="w-6 h-6 text-gray-800" />
                                </button>

                                {/* Indicators */}
                                <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex gap-2">
                                    {slides.map((_, idx) => (
                                        <button
                                            key={idx}
                                            onClick={() => setCurrent(idx)}
                                            className={`w-2 h-2 rounded-full transition-all border border-gray-400/80 ${idx === current ? 'bg-white w-6' : 'bg-white/50'
                                                }`}
                                        />
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </section>
    )
}
